validate_doc_update:
function validate_doc_update(newDoc, oldDoc, userCtx, secObj) {
  // Allow deletions and CouchDB design/internal docs through untouched.
  if (newDoc._deleted === true) return;
  if (newDoc._id && newDoc._id.indexOf("_design/") === 0) return;

  function err(field, msg) {
    throw { forbidden: "WO validation failed [" + field + "]: " + msg };
  }
  function isStr(v) { return typeof v === "string" && v.length > 0; }

  if (newDoc.type !== "workorder") err("type", "must equal 'workorder'");

  // Required fields
  ["wonum", "siteid", "description", "status", "worktype", "reportdate"].forEach(function (f) {
    if (!isStr(newDoc[f])) err(f, "is required and must be a non-empty string");
  });

  // description length cap (Maximo DESCRIPTION is 100 chars)
  if (newDoc.description.length > 100) err("description", "max length is 100 chars");

  // status enum (Maximo WO lifecycle)
  var STATUS = ["WAPPR","APPR","WMATL","WSCH","INPRG","WPCOND","COMP","CLOSE","CAN"];
  if (STATUS.indexOf(newDoc.status) === -1) err("status", "invalid status '" + newDoc.status + "'");

  // worktype enum
  var WORKTYPE = ["CM","PM","EM","PdM","CAL","INSP","GEN"];
  if (WORKTYPE.indexOf(newDoc.worktype) === -1) err("worktype", "invalid worktype '" + newDoc.worktype + "'");

  // wopriority 1..5 when present
  if (newDoc.wopriority !== undefined && newDoc.wopriority !== null) {
    var p = newDoc.wopriority;
    if (typeof p !== "number" || p < 1 || p > 5 || (p % 1 !== 0)) err("wopriority", "must be an integer 1..5");
  }

  // aob_source provenance (AssetOpsBench extension) — validate when present
  if (newDoc.aob_source) {
    var AGENTS = ["iot","fmsr","tsfm","wo","human"];
    var TRIGGERS = ["anomaly_detection","forecast","failure_mode","rule_monitoring","inspection","manual"];
    if (AGENTS.indexOf(newDoc.aob_source.agent) === -1) err("aob_source.agent", "invalid agent");
    if (TRIGGERS.indexOf(newDoc.aob_source.trigger_type) === -1) err("aob_source.trigger_type", "invalid trigger_type");
  }
}

by_scenario.map:
function map_by_scenario(doc) {
  if (doc.type === "workorder" && doc.aob_source && doc.aob_source.scenario_id) {
    emit(doc.aob_source.scenario_id, doc.wonum);
  }
}

by_agent.map:
function map_by_agent(doc) {
  if (doc.type === "workorder" && doc.aob_source && doc.aob_source.agent) {
    emit([doc.aob_source.agent, doc.aob_source.trigger_type], null);
  }
}

by_asset_class.map:
function map_by_asset_class(doc) {
  if (doc.type === "workorder" && doc.aob_asset_class) emit(doc.aob_asset_class, null);
}

backlog.map:
function map_backlog(doc) {
  // Non-terminal (open) work orders, keyed [siteid, status] for week-at-a-glance.
  var TERMINAL = { COMP: 1, CLOSE: 1, CAN: 1 };
  if (doc.type === "workorder" && !TERMINAL[doc.status]) emit([doc.siteid, doc.status], null);
}

children.map:
function map_children(doc) {
  // Task / sub-WO rows keyed by parent for breakdown lookups.
  if (doc.type === "workorder" && doc.parent) emit([doc.parent, doc.taskid || 0], doc.wonum);
}
